3336           if (Constant *SingleVal =
3337                   getFPClassConstant(VTy, Known.KnownFPClasses,
3338                                      /*IsCanonicalizing=*/true))
3339             return SingleVal;
3340 
3341           if (Known.isKnownAlways(fcInf | fcNan))
3342             return II->getArgOperand(0);
3343 
3344           return nullptr;
3345         }
3346         default:
3347           break;
3348         }
3349       }
3350     }
3351     [[fallthrough]];
3352   }
3353   default:
3354     Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3355     Known.knownNot(~DemandedMask);
3356     break;
3357   }
3358 
3359   return getFPClassConstant(VTy, Known.KnownFPClasses);
3360 }
